var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"빈 자리 아무데나 앉아. 주문은 뭘로?","JPN":"空いてるとこに座ってくれ。ご注文は？","ENG":"Take any seat you want. What would you like?","TWN":"空位都可以坐，要點什麼？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"뭘 묻고 그러나. 당연히 <color=#ffd34c>스페셜 런치</color>지.","JPN":"聞くまでもないだろう。当然<color=#ffd34c>スペシャルランチ</color>だ。","ENG":"Why do you ask? It’s the <color=#ffd34c>Special Lunch Set</color>, obviously.","TWN":"有什麼好問的，照舊，<color=#ffd34c>特色午餐</color>。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아. 턱수염이었어?","JPN":"はあ、顎ひげだったか。","ENG":"Oh, it’s you, Mr. Goatee.","TWN":"哀，是大鬍子喔？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 정도 단골이면 <color=#ffd34c>마크 핀리</color>라는 이름이 있다는 것 정도는 기억해주면 좋겠군.","JPN":"常連なんだから、<color=#ffd34c>マーク・フィンリー</color>という名前くらいは覚えてほしいがな。","ENG":"Won’t you please try to remember your regular's name? My name is <color=#ffd34c>Mark Finley</color>.","TWN":"我這麼常來，起碼該記一下常客的名字叫<color=#ffd34c>馬克·芬利</color>吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"응, 턱수염. 자리에 앉기나 해. 출입구 막지 말고.","JPN":"うん、顎ひげ。入口を塞ぐな、席につけ。","ENG":"Okay, Goatee. Have a seat. You’re blocking the entrance.","TWN":"喔。大鬍子，找個位子坐，別擋在門口。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"오늘은…… 그래. 이 자리가 좋겠군.","JPN":"今日は……そうだな、ここが良さそうだな。","ENG":"Okay... I’ll be sitting here today.","TWN":"我今天要坐……就坐這裡吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"적당히 구석이고, 햇빛도 적당히 비춰주고.","JPN":"適度に隅で、日差しもちょうどいい具合に差し込んでいる。","ENG":"It’s cozy, right here in the sun.","TWN":"在不起眼的角落，也不會曬到太多太陽。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"여기 스페셜 런치 도착이요♪","JPN":"お待たせしました！　スペシャルランチです♪","ENG":"Here is your Special Lunch Set! ♪","TWN":"這是你點的特色午餐♪"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"호오! 음식이 이렇게 빨리 나왔다는 건 날 위해 미리 준비했다는 얘긴가?","JPN":"ほう！　頼んだ料理がこんなに早く提供されるとは、私のために事前に準備してくれたのか？","ENG":"Oh, that was very fast. Were you waiting for me?","TWN":"喔喔！這麼快就端出來，應該是事前就先替我預備好的吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"환상을 깨서 미안하지만, 우연히 조리되어 있던 거야. 우연히.","JPN":"期待を裏切って悪いが、たまたま調理してたんだ。たまたまな。","ENG":"I’d hate to burst your bubble, but the dish just happened to be ready. It was a coincidence.","TWN":"做你的夢，不好意思喔，只是湊巧而已。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"응? 이거 시간 맞춰 준비해두라고 라우라 네가…….","JPN":"ん？　これって確か、時間ピッタリに用意しておけって、ラウラが……","ENG":"Huh? But you asked me to cook it in time...","TWN":"嗯？蘿拉，不是你叫我抓準時間準備……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"턱수염이 우리 카페에 1초라도 더 있는 꼴을 못 보겠어서 그랬다, 왜.","JPN":"なんだ？　顎ひげがうちのカフェから1秒でも早く出て行ってもらおうと思ったからだ。","ENG":"That’s because I didn’t want to see that hairy moron in my shop for too long.","TWN":"因為我想要大鬍子趕快吃一吃趕快滾啦，怎樣！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"후후후. 솔직하지 못한 점장님이로구만.","JPN":"フフフ。素直じゃない店長だな。","ENG":"Haha, you really speak your mind, don't you?","TWN":"呵呵呵，真是傲嬌的店長。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹~","JPN":"にゃあ～。","ENG":"Meow.","TWN":"喵喵～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"플루토, 테이블에서 뭐하는 짓이야? 빨리 안 내려와?","JPN":"プルートー、テーブルの上で何してるんだ？　早く降りてこい。","ENG":"Pluto, you’re not supposed to be on the table! Get down!","TWN":"布魯托，你在桌子上幹嘛？還不快下來？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"오! 괜찮네. 드디어 이 명물 고양이의 실물을 가까이에서 영접하는군!","JPN":"おお！　これは嬉しいな。やっとこの名物ネコ君の実物が見られたな！","ENG":"Oh, it’s okay! I finally get to see the famous kitty up close!","TWN":"沒關係！終於可以近距離目睹人氣店貓本尊！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭔가 착각한 거 아냐? 플루토는 그냥 고양이야.","JPN":"何か勘違いしてないか？　プルートーはただのネコだぞ？","ENG":"You must be mistaken. Pluto is just an ordinary cat.","TWN":"你是不是有什麼誤會？布魯托就只是一隻普通的貓而已。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐아옹, 냐옹?","JPN":"にゃああ、にゃあ？","ENG":"Meow, meow?","TWN":"喵，喵喵？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"자긴 평범한 고양이가 아니라고 하는 것 같은데? 아주 똑똑한 녀석이야.","JPN":"自分はただのネコじゃないって言っているようだな。実に賢い子だ。","ENG":"He says he’s not an ordinary cat. What a smart guy.","TWN":"牠好像是在說牠不是一隻普通的貓，真是隻聰明的貓咪。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……그걸 알아듣는 네가 더 대단한 것 같은데?","JPN":"……そう聞こえてる汝のほうがすごいと思うが？","ENG":"How can you understand him?","TWN":"……你聽得懂牠的話才厲害吧？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"모름지기 정보부 사람이라면 어떤 누구의 말에도 귀 기울일 줄 알아야지.","JPN":"情報局の人間なら、あらゆる生き物の言葉に耳を傾けないとな。","ENG":"I’m an intelligence officer. It’s my job to understand anything that anyone says.","TWN":"身為情報部的人，聽懂任何生物的話是應該的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"어떻게 이런 영민한 고양이의 집사가 된 건지 얘기해줄 수 있겠나? 비법이 궁금하군.","JPN":"こんな賢い猫の下僕になった経緯を聞かせてもらえないだろうか。秘訣が知りたい。","ENG":"How did you become a slave to this intelligent cat? I would love to know.","TWN":"你可以跟我說說，你是如何成為貓奴的嗎？我很好奇你是怎麼辦到的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"내가 집사인 게 아니라, 얘가 내 사역마야. 착각하지 마.","JPN":"妾を下僕扱いするんじゃない。この子が妾の使い魔なんだ。勘違いするな。","ENG":"I am not his slave. HE is my familiar. Don’t get it confused.","TWN":"你別誤會，我才不是貓奴，牠是我的召喚獸。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"후후. 그렇지, 그런 거지. 후후후.","JPN":"フフ、だろうね。そうだとも、フフフ。","ENG":"Haha. Of course, of course.","TWN":"呵呵呵，好好好，呵呵呵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……내 말은 전혀 안 듣는구나, 너.","JPN":"……まったく、聞いちゃいないな。","ENG":"You’re not listening at all, are you?","TWN":"……你根本沒在聽我說話吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이 녀석은…….","JPN":"この子は……","ENG":"I met him...","TWN":"這傢伙是……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……내가 이곳에 처음 왔을 때였나?","JPN":"……妾が初めてここに来た頃のことだ。","ENG":"... when I first came here.","TWN":"……我第一次到這個地方的時候嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"웬 새끼고양이가 귀찮게 따라다니길래 주워 왔어.","JPN":"知らない仔猫がしつこく付きまとってきたから、拾ってきたのだ。","ENG":"A kitten followed me around, so I took him in.","TWN":"因為有隻小貓一直跟著我，我覺得很煩才把牠撿回來的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"호오. 그랬군?","JPN":"ほほう、なるほど？","ENG":"Oh, I see.","TWN":"喔嗚，原來是這樣。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그런 걸 바로 간택 당했다고 한다네.","JPN":"それを「猫に選ばれた」と言うんだ。","ENG":"That’s how you become a slave to your cat.","TWN":"牠選上你了啦。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그게 아니라니까. 자꾸 날 집사 따위로 만들 셈이야?","JPN":"そうじゃないって言ってるだろう。どうしても妾を下僕扱いしたいのか？","ENG":"I’m telling you, I am not his slave.","TWN":"就跟你說不是這樣，幹嘛一直要把我弄成是貓奴？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐오옹.","JPN":"にゃ～。","ENG":"Meow.","TWN":"喵喵。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 그때나 지금이나 귀찮아 죽겠군.","JPN":"ふん、あの時も今も鬱陶しいな。","ENG":"Hmpf. He’s such a hassle, then and now.","TWN":"哼，不管是那時候還是現在，牠都一樣很煩。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……주워 온 거 맞는데.","JPN":"……妾が拾ってやったのに。","ENG":"...Well, I did pick him up off the street.","TWN":"……是我把牠撿回來的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐야. 귀찮게.","JPN":"何だ、面倒くさい。","ENG":"Hey, stop bugging me.","TWN":"幹嘛啦，很煩欸。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"먀옹~","JPN":"にゃあ～。","ENG":"Meow.","TWN":"喵～"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"저리 가. 너랑 말 섞을 기분 아니니까.","JPN":"あっちに行け、お前とじゃれ合う気分じゃないんだ。","ENG":"Go away, I’m not in the mood to talk to you.","TWN":"走開，我現在沒心情理你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"왜 자꾸 따라와? 저리 안 가?","JPN":"なんで離れない？　あっちに行けってば。","ENG":"Why are you following me? Shoo!","TWN":"幹嘛一直跟著我啦？走開！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"먀옹! 미야옹!","JPN":"にゃあ！　にゃああ！","ENG":"Meow! Meow!","TWN":"喵！喵喵喵！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐. 너무 옹알거려서 뭐라는지 하나도 모르겠거든?","JPN":"何だ、にゃあにゃあにゃあにゃあって、何を言ってるのかさっぱりわからん。","ENG":"Hey, I don’t understand a word you’re saying.","TWN":"你喵得再起勁我也聽不懂啦。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"시끄럽게 굴지 말고 좀 가라고.","JPN":"いい加減離れろ、あっち行け。","ENG":"I told you, stop bugging me. Go climb a tree.","TWN":"所以別煩我了，快走開。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……!! 이거 놔! 옷 찢어져!!","JPN":"……！！　放せ！　服が破けるだろう！！","ENG":"Let go! You’ll rip my clothing!","TWN":"……！！鬆開！衣服會被你抓破啦！！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하찮은 미물 주제에 감히 마녀한테 이빨을 들이대?","JPN":"身の程知らずが、魔女に牙をむくとは！","ENG":"Such an insignificant creature dares to attack a witch?","TWN":"你這隻三腳貓竟敢對魔女出手？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"안 그래도 짜증났는데 너 잘 만났…….","JPN":"憂さ晴らしにちょうどいい……","ENG":"You’ll pay for this—","TWN":"正好我心情不佳，就拿你來……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"뭐, 뭐야?!","JPN":"なっ、何だ！？","ENG":"W-what happened?","TWN":"怎…怎麼回事？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이건……. 싱크홀?","JPN":"これは……シンクホール？","ENG":"Is this a sinkhole?","TWN":"這是……天坑？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"조금만 더 갔으면 꼼짝없이 빠질 뻔했네. ……설마.","JPN":"あと少しで落ちるところだった。……まさか。","ENG":"If I kept going, I could have fallen in... Wait.","TWN":"再稍微往前一點肯定會掉進去的……難道？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"미야옹~","JPN":"にゃあ～。","ENG":"Meow.","TWN":"喵喵～"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"흥. 쓸데없는 짓을 했군. 나는 마녀라 싱크홀 따위는 문제되지 않아.","JPN":"ふん、余計なことを。妾は魔女だから、シンクホールなんて問題にならない。","ENG":"Hmpf, that wasn’t necessary, cat. I’m a witch, and a sinkhole can’t hurt me.","TWN":"哼，要你多管閒事，我可是個魔女，天坑這種東西我才不怕。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그보다 그만 좀 따라오지? 어디까지 따라올 셈이야?","JPN":"それより、そろそろいい加減にしろ。どこまでついて来る気なんだ？","ENG":"Also, stop following me. You can’t come with me.","TWN":"倒是你，拜託別再跟著我了，你是打算跟到什麼時候？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_EXTRA_NULL_NULL","text":{"KOREA":"미야오옹…….","JPN":"にゃああ……","ENG":"Meow...","TWN":"喵…喵…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"하아. 이럴 속셈으로 접근한 거 아냐, 이거?","JPN":"はあ、最初からこれ目的で近づいてきたのか？","ENG":"*Sigh* You knew this was going to happen, didn’t you?","TWN":"哀，這就是你接近我的目的吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……먹을 건 알아서 구해다 먹어. 사역마 정도로는 임명해줄 테니까.","JPN":"……エサくらいは自分で調達しろ。それなら、使い魔として任命してやってもいい。","ENG":"... I will take you in as my familiar. But you’ll have to find your own food.","TWN":"……吃的東西你自己負責，就任命你為我的召喚獸吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……플루토.","JPN":"……プルートー。","ENG":"... Pluto.","TWN":"……布魯托。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"잘 먹었네. 내일 또 오지.","JPN":"ごちそうさま。また明日来るよ。","ENG":"Thank you for the meal. I’ll stop by again tomorrow.","TWN":"我吃飽囉，明天會再來的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹!","JPN":"にゃあ！","ENG":"Meow!","TWN":"喵！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L33_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"응? 이, 이것 좀 놔주지 않겠나?","JPN":"ん？　こ、こら、なぜ離さないんだ？","ENG":"Huh? C-could you please let go?","TWN":"嗯？可以鬆開爪子嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"턱수염 옷 찢어져! 네가 배상하려고 그래?!","JPN":"こら、やめろ！　顎ひげの服が破けたら汝が弁償するのか！？","ENG":"Hey, you’ll rip Mr. Goatee’s clothes! Are you going to pay for it?","TWN":"大鬍子的衣服被你抓破的話你要賠嗎？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그건 괜찮네만……. 왜 이러는지 도통 알 수가 없군.","JPN":"それは大丈夫だが……突然どうしたんだろうな。","ENG":"The clothing’s alright... But why is he acting like this?","TWN":"衣服是無所謂……只是牠怎麼突然這麼激動？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹! 냐오옹!","JPN":"にゃあ！　にゃああ！","ENG":"Meow! Meooow!","TWN":"喵喵！喵喵喵！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이왕 붙잡힌 김에 플루토가 놔줄 때까지 놀아주고 가.","JPN":"こうなった以上、プルートーの気が済むまで遊んでやったらどうだ？","ENG":"Well, since Pluto won’t let you go, why don’t you stay here and spend some time with him?","TWN":"既然如此，那在牠鬆開前你就陪牠玩一下吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"나 바쁜 사람이네만……?","JPN":"こう見えてかなり多忙なんだが……？","ENG":"I’m a busy man, you know.","TWN":"我可是個大忙人欸……？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그럼 뭐, 물고 있는데 어쩔 거야. 데려가기라도 할 거야?","JPN":"こうやって離さないんだからしょうがないだろう。それとも、このまま連れていくか？","ENG":"Then what are you going to do? He won’t let go. Are you going to take him with you?","TWN":"不然怎麼辦？牠就不鬆開，不然你要把牠整隻帶走嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그것도 좋…….","JPN":"それも悪くな……","ENG":"Oh, I would love to...","TWN":"這主意不錯……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아. 놨다. 턱수염한테 끌려가긴 싫었나 보지? 이해해.","JPN":"あ、やっと離した。さすがに顎ひげに連れていかれたくはなかったか、わかるぞ。","ENG":"Oh, he let go. He doesn’t want to go with Mr. Goatee. I understand the sentiment.","TWN":"喔？鬆開了。看來牠不想跟大鬍子走喔？嘿嘿嘿。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"기분이 영 찜찜한데?","JPN":"なんだか複雑な気分だな……","ENG":"Hmm, what was that about?","TWN":"怎麼有點不是滋味？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"아무튼 이렇게 쉽게 보내주니 괜히 또 서운하군. 내일 보도록 하지, 명물 고양이.","JPN":"こう簡単に離されてしまうと逆にさみしいな。また明日な、名物ネコ君。","ENG":"Now that he let go of me, I feel so disheartened. I’ll see you tomorrow, famous kitty.","TWN":"就這樣放牠走好像又有點失落呢。我明天再來看你吧，人氣店貓。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"……플루토.","JPN":"……プルートー。","ENG":"... Pluto.","TWN":"……布魯托。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냥?!","JPN":"にゃ～！？","ENG":"Meow?","TWN":"喵？！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아까 왜 그런 거야?","JPN":"さっきはどうしたのだ？","ENG":"Why did you do that?","TWN":"你剛才為什麼抓人家的衣服？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐…… 냐옹. 냐옹~","JPN":"にゃあ……にゃ～にゃ～。","ENG":"Meow... meow. Meow.","TWN":"喵……喵喵，喵～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"응? 뭐 두고 갔어?","JPN":"ん？　忘れ物？","ENG":"What is it? You forgot something?","TWN":"嗯？是落掉什麼東西嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"내, 내 앞에……! 화, 화……!!","JPN":"め、目の前に……！　う、う……！！","ENG":"A p... p...! Dropped i...!","TWN":"花…花…！我…我腳前…！！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"일단 진정 좀 해. 다 큰 어른이 무슨 추태야?","JPN":"とりあえず落ち着け。大の大人がみっともないぞ？","ENG":"Hey, calm down. You’re embarrassing yourself.","TWN":"你先冷靜點，都這麼大的人了，嚇成這樣像話嗎？"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"자아. 심호흡 하시고.","JPN":"さあ、深呼吸して。","ENG":"Come on, take a deep breath.","TWN":"來，先深呼。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"마음을 편안하게 해주는 라벤더 허브티랍니다. 마시면 좀 진정 될 거예요♪","JPN":"リラックス効果があるラベンダーハーブティーです。飲んだら少し落ち着きますよ♪","ENG":"Here, this lavender tea will calm you down. You’ll be fine soon. ♪","TWN":"薰衣草茶可以幫助穩定情緒，你先喝一杯冷靜一下吧♪"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"후욱. 후우.","JPN":"ゴクゴク、ふう……","ENG":"*Huff* *Huff*","TWN":"呼～呼～呼～呼～"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"……좀 낫군. 고맙네.","JPN":"……少し落ち着いたよ、ありがとう。","ENG":"That’s better. Thank you.","TWN":"……有好一點了，謝謝你。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"대체 무슨 일이야? 평소에 흐트러짐 하나 없던 양반이.","JPN":"いったいどうしたんだ？　いつも落ち着き払っているやつが。","ENG":"What’s wrong? I’ve never seen you so flustered.","TWN":"到底怎麼回事？平時明明沒什麼事可以嚇到你的。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그러니까, 밖으로 나갔더니 말이야.","JPN":"それが、外に出たら……","ENG":"You see, when I walked out the door...","TWN":"就我剛走出去後，"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"갑자기 물벼락이 쏟아지지 뭔가. 몇 걸음만 더 갔어도 쫄딱 젖은 모양새였을 거야.","JPN":"いきなり上から水が降ってきたんだ。あと数歩でずぶ濡れになるところだったよ。","ENG":"A huge cascade of water crashed down from above. I would have been soaked if I'd taken a few more steps.","TWN":"突然有水潑下來，再往前走幾步的話肯定會渾身濕。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_DIVE_02"},{"id":"L30_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"소나기라도 온 거야?","JPN":"通り雨か？","ENG":"Was it rain?","TWN":"是突然下大雨喔？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"사람 지나가는 줄 모르고 위에서 쏟아버렸다고 하더군.","JPN":"いや、人が通ることに気づかず、上から水を捨てていたみたいでな。","ENG":"No, someone poured water from above. They said they didn’t see me.","TWN":"是有人沒看到底下有人經過，就從上面倒水下來。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"놀라서 심장 부여잡다가, 진정하고는 다시 발을 뗐지.","JPN":"とても驚いたが、ようやく落ち着いてまた足を踏み出したんだ。","ENG":"Anyway, I kept going, trying to calm my pounding heart.","TWN":"我冷靜一下後又繼續往前走。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L33_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그런데 이번엔 무법질주 오토바이가 내 앞을 아슬아슬하게 지나가더란 말이지.","JPN":"だが、今度は暴走中のバイクが私の前をスレスレで通ったんだ。","ENG":"But then, a crazy biker almost hit me!","TWN":"結果有一台不要命的摩托車從我面前疾駛而過。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L34_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"바람이 일 정도로 가까웠다네. 아무튼 또 놀란 마음 부여잡고 발을 떼려는데……","JPN":"風を切る音が聞こえるくらい近かった。まあ、とにかくまた気持ちを落ち着かせて歩き出そうとしたら……","ENG":"I could almost feel the slipstream. And when I started to walk away...","TWN":"整個離我超近的，害我又嚇到。後來冷靜過後又要繼續往前……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이번엔 또 뭔데?","JPN":"今度は何だ？","ENG":"What happened this time?","TWN":"這次又是什麼？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"내 코앞으로 커다란 화분이 떨어지지 않겠나!","JPN":"目の前に大きな植木鉢が落ちてきたんだ！","ENG":"A huge potted plant fell right in front of me!","TWN":"突然有一個大花盆掉下來，就剛好掉到我的腳前！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L38_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"놀라서 다시 이곳으로 달려왔네!","JPN":"それで驚いてここまで走ってきたのさ！","ENG":"I was too shocked, so I had to come back!","TWN":"我太驚嚇了，所以就跑回來這裡！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"놀라면 놀란 거지, 왜 여길 다시 들어와?","JPN":"ビックリしたのはわかるが、なぜ戻ってきたんだ？","ENG":"But why would you come back here?","TWN":"嚇到就嚇到，跑回來這裡幹嘛？"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 고양이가 날 잡아서 잠시 늦게 간 덕에 이 모든 재앙을 피한 것 아닌가!","JPN":"このネコ君が私を引き留めてくれたおかげで災いをすべて回避できたではないか！","ENG":"Because this cat saved me from all these disastrous events!","TWN":"要不這隻貓咪抓住我，這些災難可能都會臨到我！牠是我的福星！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"역시 불행을 점쳐주는 명물 고양이는 다르군, 달라.","JPN":"さすが、災いを予見する名物ネコ君だ。","ENG":"You really are an amazing cat, who can predict misfortune.","TWN":"可以幫人趨吉避凶的店貓果然不同凡響，厲害！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"고맙네! 네가 날 살렸어!!","JPN":"ありがとう！　君は私の命の恩人だ！！","ENG":"Thank you! You saved my life!","TWN":"謝謝你！我的救命恩貓！！"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐아옹~","JPN":"にゃああ～。","ENG":"Meow!","TWN":"喵～"},"stage":{"bg":"CAFE_STREGA","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"나 참. 뭐 큰일 했나 했네. 내 사역마한테 그 정도는 일도 아니지.","JPN":"なんだ、大したことないじゃないか。妾の使い魔なんだから、それくらいは当然だ。","ENG":"No big deal. He’s my familiar; that’s easy for him.","TWN":"真是的，我還以為是什麼大事呢，這對我的召喚獸而言只是小菜一碟啦！"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"구한 사람이 턱수염이라는 게 마음에 안 들지만, 어쨌든 사람 한 명 구한 거니까.","JPN":"助けたのが顎ひげなのは気に食わないが、まあとにかく一人の人間を救ったんだ。","ENG":"I don’t know why he wanted to save Mr. Goatee, but I guess every life matters.","TWN":"雖然我不是很開心牠救的是你，但牠確實是有救到人啦。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"고급 정어리 캔 하나 정도는 따줄게.","JPN":"高級イワシ缶の一つくらいはあげるとするか。","ENG":"Okay, I’ll give you a tasty mackerel can as a reward.","TWN":"就開一個高級沙丁魚罐罐給你吧。"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹♥","JPN":"にゃあ～♥","ENG":"Meow ♥","TWN":"喵喵♥"},"stage":{"bg":"CAFE_STREGA","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_START"}]`);export{e as default};